--
-- Struktur untuk view `v_daily_stats`
--
DROP TABLE IF EXISTS `v_daily_stats`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_daily_stats`  AS SELECT cast(`json_backup`.`backup_timestamp` as date) AS `tanggal`, count(0) AS `total_sesi`, sum(`json_backup`.`total_records`) AS `total_records`, avg(`json_backup`.`data_size_kb`) AS `avg_size_kb`, avg(cast(replace(`json_backup`.`node_completeness`,'%','') as decimal(5,2))) AS `avg_completeness`, min(`json_backup`.`backup_timestamp`) AS `first_sync`, max(`json_backup`.`backup_timestamp`) AS `last_sync` FROM `json_backup` GROUP BY cast(`json_backup`.`backup_timestamp` as date) ORDER BY cast(`json_backup`.`backup_timestamp` as date) DESC ;

-- --------------------------------------------------------

--
-- Struktur untuk view `v_latest_sessions`
--
DROP TABLE IF EXISTS `v_latest_sessions`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_latest_sessions`  AS SELECT `jb`.`id` AS `id`, `jb`.`sesi_id_getdata` AS `sesi_id_getdata`, `jb`.`total_records` AS `total_records`, `jb`.`node_completeness` AS `node_completeness`, `jb`.`data_size_kb` AS `data_size_kb`, `jb`.`backup_timestamp` AS `backup_timestamp`, `gl`.`waktu_mulai` AS `waktu_mulai`, `gl`.`waktu_selesai` AS `waktu_selesai`, `gl`.`node_sukses` AS `node_sukses`, `gl`.`node_gagal` AS `node_gagal`, timestampdiff(SECOND,`gl`.`waktu_mulai`,`gl`.`waktu_selesai`) AS `duration_seconds` FROM (`json_backup` `jb` left join `getdata_logs` `gl` on(`jb`.`sesi_id_getdata` = `gl`.`sesi_id_getdata`)) ORDER BY `jb`.`id` DESC ;

-- --------------------------------------------------------

--
-- Struktur untuk view `v_node_activity`
--
DROP TABLE IF EXISTS `v_node_activity`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `v_node_activity`  AS SELECT `nl`.`node_id` AS `node_id`, `n`.`group` AS `group`, `n`.`kode_perlakuan` AS `kode_perlakuan`, count(0) AS `total_logs`, sum(case when `nl`.`status` = 'Aktif' then 1 else 0 end) AS `active_count`, sum(case when `nl`.`status` = 'Non Aktif' then 1 else 0 end) AS `inactive_count`, avg(`nl`.`rssi_dbm`) AS `avg_rssi`, avg(`nl`.`snr_db`) AS `avg_snr`, max(`nl`.`waktu`) AS `last_activity` FROM (`node_logs` `nl` left join `node` `n` on(`nl`.`node_id` = `n`.`node_id`)) WHERE `nl`.`waktu` >= current_timestamp() - interval 7 day GROUP BY `nl`.`node_id`, `n`.`group`, `n`.`kode_perlakuan` ORDER BY `nl`.`node_id` ASC ;
COMMIT;

